import React, { useEffect, useState } from 'react';

interface ToastProps {
  message: string;
  type: 'success' | 'error' | 'info' | 'warning';
  onClose: () => void;
  duration?: number;
}

const TONES = {
  success: {
    bar:    '#16a34a',
    bg:     '#f0fdf4',
    border: '#bbf7d0',
    text:   '#14532d',
    title:  'Success',
  },
  error: {
    bar:    '#dc2626',
    bg:     '#fef2f2',
    border: '#fecaca',
    text:   '#7f1d1d',
    title:  'Something went wrong',
  },
  warning: {
    bar:    '#d97706',
    bg:     '#fffbeb',
    border: '#fde68a',
    text:   '#78350f',
    title:  'Heads up',
  },
  info: {
    bar:    '#2563eb',
    bg:     '#eff6ff',
    border: '#bfdbfe',
    text:   '#1e3a8a',
    title:  'Info',
  },
};

export default function Toast({ message, type, onClose, duration = 4000 }: ToastProps) {
  const [closing, setClosing] = useState(false);
  const c = TONES[type];

  useEffect(() => {
    const t = setTimeout(() => {
      setClosing(true);
      setTimeout(onClose, 180);
    }, duration);
    return () => clearTimeout(t);
  }, [onClose, duration]);

  return (
    <div role="status" aria-live="polite"
      style={{
        position: 'fixed', bottom: 24, right: 24, zIndex: 9999,
        display: 'flex', minWidth: 320, maxWidth: 420,
        background: c.bg,
        border: `1px solid ${c.border}`,
        borderRadius: 10,
        boxShadow: '0 12px 32px rgba(16,24,40,0.10), 0 4px 12px rgba(16,24,40,0.06)',
        overflow: 'hidden',
        animation: closing ? 'toastOut .18s ease forwards' : 'toastIn .22s cubic-bezier(.16,1,.3,1) forwards',
        fontFamily: 'inherit',
      }}>
      <style>{`
        @keyframes toastIn  { from { opacity: 0; transform: translateY(8px) scale(.98); } to { opacity: 1; transform: translateY(0) scale(1); } }
        @keyframes toastOut { from { opacity: 1; transform: translateY(0); }            to { opacity: 0; transform: translateY(8px); } }
        @keyframes toastTimer { from { transform: scaleX(1); } to { transform: scaleX(0); } }
      `}</style>

      <div style={{ width: 4, background: c.bar, flexShrink: 0 }} />

      <div style={{ flex: 1, padding: '12px 14px 14px', minWidth: 0 }}>
        <div style={{
          fontSize: 13, fontWeight: 600, color: c.text,
          marginBottom: 2,
        }}>{c.title}</div>
        <div style={{
          fontSize: 13, color: c.text, opacity: 0.85,
          lineHeight: 1.45,
          wordBreak: 'break-word',
        }}>{message}</div>

        {/* Timer bar */}
        <div style={{
          height: 2, marginTop: 10, background: 'transparent',
          borderRadius: 99, overflow: 'hidden',
        }}>
          <div style={{
            height: '100%', width: '100%',
            background: c.bar, opacity: 0.5,
            transformOrigin: 'left center',
            animation: `toastTimer ${duration}ms linear forwards`,
          }}/>
        </div>
      </div>

      <button onClick={() => { setClosing(true); setTimeout(onClose, 180); }}
        aria-label="Dismiss"
        style={{
          background: 'transparent', border: 'none',
          color: c.text, opacity: 0.55,
          padding: '8px 12px', cursor: 'pointer',
          fontSize: 18, lineHeight: 1, fontFamily: 'inherit',
          alignSelf: 'flex-start',
        }}>×</button>
    </div>
  );
}
